module top_module(
  input aclk,
  input areset,
  output reg [3:0] cnt,
  output reg overflow
);always @(posedge aclk) begin
    if (areset) begin
      cnt <= 4'b0000;
      overflow <= 1'b0;
    end
    else begin
      if (cnt == 4'b1111) begin
        cnt <= 4'b0000;
        overflow <= 1'b1;
      end
      else begin
        cnt <= cnt + 1;
        overflow <= 1'b0;
      end
    end
  end

endmodule
